document.addEventListener("DOMContentLoaded",()=>{const t=document.querySelectorAll(".timer"),e=document.querySelector("#endtime").getAttribute("data-end-time"),n=function(t){const e=(t=t.trim().replace(/\u00A0|\u2000-\u200B/g," ")).split(/\s+/);if(e.length<2)return null;let n=e[0],o=e[1].replace(/[-,]/g,":");if(n.includes(".")){const[t,e,r]=n.split(".");if(!t||!e||!r)return null;const[l,u]=o.split(":"),d=new Date(Number(r),Number(e)+1,Number(t),Number(l),Number(u),0);return isNaN(d.getTime())?null:d}if(n.includes("-")){const t=new Date(`${n}T${o}:00`);return isNaN(t.getTime())?null:t}return null}(e);console.log("end",n),n?t.forEach(()=>{function t(){const t=new Date,e=n-t;if(e<=0){document.getElementById("days").textContent="00",document.getElementById("hours").textContent="00",document.getElementById("minutes").textContent="00",document.getElementById("seconds").textContent="00";const t=document.querySelector(".section-timer");return void(t&&(t.style.display="none"))}const o=Math.floor(e/1e3),r=Math.floor(o/86400),l=Math.floor(o%86400/3600),u=Math.floor(o%3600/60),d=o%60;document.getElementById("days").textContent=String(r).padStart(2,"0"),document.getElementById("hours").textContent=String(l).padStart(2,"0"),document.getElementById("minutes").textContent=String(u).padStart(2,"0"),document.getElementById("seconds").textContent=String(d).padStart(2,"0")}t(),setInterval(t,1e3)}):console.error("Failed to parse date:",e)});